    report += `- WebGL1: ${deviceCapabilities.webGL1Supported ? '✓' : '✗'}\n`;
    report += `- Audio Context: ${deviceCapabilities.audioContextSupported ? '✓' : '✗'}\n`;
    report += `- CPU Cores: ${deviceCapabilities.hardwareConcurrency}\n`;
    if (deviceCapabilities.deviceMemory) {
      report += `- Device Memory: ${deviceCapabilities.deviceMemory}GB\n`;
    }
    report += `- Performance.now() Resolution: ${deviceCapabilities.performanceNowResolution.toFixed(3)}ms\n\n`;

    report += '## Frame Rate Performance\n';
    report += `- Target FPS: ${fpsMetrics.targetFps}\n`;
    report += `- Actual FPS: ${fpsMetrics.actualFps.toFixed(1)}\n`;
    report += `- FPS Variance: ${fpsMetrics.fpsVariance.toFixed(2)}\n`;
    report += `- Frame Time Variance: ${fpsMetrics.frameTimeVariance.toFixed(2)}ms\n`;
    report += `- Dropped Frames: ${fpsMetrics.droppedFrames}\n\n`;

    report += '## Timing Precision\n';
    report += `- Clock Resolution: ${timingPrecision.clockResolution.toFixed(0)}μs\n`;
    report += `- Drift Rate: ${(timingPrecision.driftRate * 100).toFixed(3)}%\n`;
    report += `- Timing Jitter: ${timingPrecision.jitter.toFixed(2)}ms\n`;
    report += `- Max Deviation: ${timingPrecision.maxDeviation.toFixed(2)}ms\n\n`;

    report += '## Compatibility Assessment\n';
    report += `- 2ms Precision: ${compatibilityMatrix.canRun2msPrecision ? '✓ Supported' : '✗ Not Supported'}\n`;
    report += `- 5ms Precision: ${compatibilityMatrix.canRun5msPrecision ? '✓ Supported' : '✗ Not Supported'}\n`;
    report += `- 16ms Precision: ${compatibilityMatrix.canRun16msPrecision ? '✓ Supported' : '✗ Not Supported'}\n`;
    report += `- Recommended Frame Rate: ${compatibilityMatrix.recommendedFrameRate} FPS\n\n`;

    if (compatibilityMatrix.warnings.length > 0) {
      report += '## Warnings\n';
      compatibilityMatrix.warnings.forEach(warning => {
        report += `- ⚠️ ${warning}\n`;
      });
    }

    return report;
  }
}

