import { describe, it, expect, beforeEach, vi } from 'vitest';
import { HardwareTimingValidator } from './HardwareTimingValidator';

describe('HardwareTimingValidator', () => {
  let validator: HardwareTimingValidator;

  beforeEach(() => {
    validator = new HardwareTimingValidator();

    // Mock browser APIs
    vi.spyOn(global, 'performance', 'get').mockReturnValue({
      now: vi.fn(() => Date.now()),
      memory: {
        usedJSHeapSize: 50 * 1024 * 1024,
        totalJSHeapSize: 100 * 1024 * 1024,
        jsHeapSizeLimit: 2048 * 1024 * 1024
      }
    } as any);

    vi.spyOn(global, 'screen', 'get').mockReturnValue({
      height: 1080,
      refreshRate: 60
    } as any);

    vi.spyOn(global.navigator, 'hardwareConcurrency', 'get').mockReturnValue(8);
    vi.spyOn(global.navigator, 'userAgent', 'get').mockReturnValue('Test Browser');
    vi.spyOn(global.navigator, 'platform', 'get').mockReturnValue('Test Platform');

    // Mock AudioContext
    global.AudioContext = vi.fn(() => ({
      currentTime: 0,
      close: vi.fn()
    })) as any;

    // Mock requestAnimationFrame
    let frameId = 0;
    global.requestAnimationFrame = vi.fn((callback) => {
      const id = ++frameId;
      setTimeout(() => callback(Date.now()), 16);
      return id;
    }) as any;

    // Mock HTMLVideoElement
    Object.defineProperty(HTMLVideoElement.prototype, 'requestVideoFrameCallback', {
      value: vi.fn(),
      configurable: true
    });
  });

  describe('detectCapabilities', () => {
    it('should detect browser capabilities correctly', async () => {
      const result = await validator.validate({ testDuration: 100 });

      expect(result.deviceCapabilities).toBeDefined();
      expect(result.deviceCapabilities.audioContextSupported).toBe(true);
      expect(result.deviceCapabilities.hardwareConcurrency).toBe(8);
      expect(result.deviceCapabilities.platform).toBe('Test Platform');
      expect(result.deviceCapabilities.requestVideoFrameCallbackSupported).toBe(true);
    });

    it('should handle missing WebGL support', async () => {
      // Mock canvas context to return null
      const mockCanvas = {
        getContext: vi.fn(() => null)
      };
      vi.spyOn(document, 'createElement').mockReturnValue(mockCanvas as any);

      const result = await validator.validate({ testDuration: 100 });

      expect(result.deviceCapabilities.webGL2Supported).toBe(false);
      expect(result.deviceCapabilities.webGL1Supported).toBe(false);
      expect(result.compatibilityMatrix.warnings).toContainEqual(
        expect.stringContaining('No WebGL support')
      );
    });
  });

  describe('frame rate testing', () => {
    it('should measure frame rate stability', async () => {
      const result = await validator.validate({ 
        testDuration: 200,
        targetFps: 60 
      });

      expect(result.fpsMetrics).toBeDefined();
      expect(result.fpsMetrics.targetFps).toBe(60);
      expect(result.fpsMetrics.actualFps).toBeGreaterThan(0);
      expect(result.fpsMetrics.testDuration).toBe(200);
    });

    it('should detect dropped frames', async () => {
      // Mock requestAnimationFrame to simulate dropped frames
      let callCount = 0;
      global.requestAnimationFrame = vi.fn((callback) => {
        callCount++;
        // Simulate dropped frame every 5th frame
        const delay = callCount % 5 === 0 ? 50 : 16;
        setTimeout(() => callback(Date.now()), delay);
        return callCount;
      }) as any;

      const result = await validator.validate({ 
        testDuration: 300,
        targetFps: 60 
      });

      expect(result.fpsMetrics.droppedFrames).toBeGreaterThan(0);
    });
  });

  describe('timing precision testing', () => {
    it('should measure clock resolution', async () => {
      const result = await validator.validate({ testDuration: 100 });

      expect(result.timingPrecision).toBeDefined();
      expect(result.timingPrecision.clockResolution).toBeGreaterThan(0);
      expect(result.timingPrecision.driftRate).toBeDefined();
      expect(result.timingPrecision.jitter).toBeDefined();
      expect(result.timingPrecision.maxDeviation).toBeDefined();
    });
  });

  describe('compatibility determination', () => {
    it('should determine 2ms precision capability', async () => {
      const result = await validator.validate({ testDuration: 100 });

      expect(result.compatibilityMatrix).toBeDefined();
      expect(typeof result.compatibilityMatrix.canRun2msPrecision).toBe('boolean');
      expect(typeof result.compatibilityMatrix.canRun5msPrecision).toBe('boolean');
      expect(typeof result.compatibilityMatrix.canRun16msPrecision).toBe('boolean');
      expect(result.compatibilityMatrix.recommendedFrameRate).toBeGreaterThan(0);
    });

    it('should always support 16ms precision', async () => {
      const result = await validator.validate({ testDuration: 100 });

      expect(result.compatibilityMatrix.canRun16msPrecision).toBe(true);
    });

    it('should generate warnings for poor performance', async () => {
      // Simulate high jitter
      let time = 0;
      global.performance.now = vi.fn(() => {
        time += Math.random() * 10; // High jitter
        return time;
      });

      const result = await validator.validate({ testDuration: 200 });

      expect(result.compatibilityMatrix.warnings.length).toBeGreaterThan(0);
    });
  });

  describe('report generation', () => {
    it('should generate a human-readable report', async () => {
      const result = await validator.validate({ testDuration: 100 });
      const report = validator.generateReport(result);

      expect(report).toContain('Hardware Timing Validation Report');
      expect(report).toContain('Device Capabilities');
      expect(report).toContain('Frame Rate Performance');
      expect(report).toContain('Timing Precision');
      expect(report).toContain('Compatibility Assessment');
    });

    it('should include warnings in report when present', async () => {
      // Force a warning condition
      const mockCanvas = {
        getContext: vi.fn(() => null)
      };
      vi.spyOn(document, 'createElement').mockReturnValue(mockCanvas as any);

      const result = await validator.validate({ testDuration: 100 });
      const report = validator.generateReport(result);

      expect(report).toContain('Warnings');
      expect(report).toContain('⚠️');
    });
  });

  describe('memory metrics', () => {
    it('should capture memory metrics when available', async () => {
      const result = await validator.validate({ testDuration: 100 });

      expect(result.memoryMetrics).toBeDefined();
      expect(result.memoryMetrics.heapUsed).toBe(50 * 1024 * 1024);
      expect(result.memoryMetrics.heapTotal).toBe(100 * 1024 * 1024);
      expect(result.memoryMetrics.heapLimit).toBe(2048 * 1024 * 1024);
    });

    it('should handle missing memory API', async () => {
      vi.spyOn(global, 'performance', 'get').mockReturnValue({
        now: vi.fn(() => Date.now())
      } as any);

      const result = await validator.validate({ testDuration: 100 });

      expect(result.memoryMetrics.heapUsed).toBe(0);
      expect(result.memoryMetrics.heapTotal).toBe(0);
      expect(result.memoryMetrics.heapLimit).toBe(0);
    });
  });
});

