#!/usr/bin/env node

/**
 * CLI tool for running hardware timing validation
 * Can be used in CI/CD pipelines to validate timing capabilities
 */

import { HardwareTimingValidator } from '../HardwareTimingValidator';
import { writeFileSync } from 'fs';
import { join } from 'path';

interface CLIOptions {
  duration: number;
  targetFps: number;
  output?: string;
  json?: boolean;
  failOn2ms?: boolean;
  failOn5ms?: boolean;
}

function parseArgs(): CLIOptions {
  const args = process.argv.slice(2);
  const options: CLIOptions = {
    duration: 3000,
    targetFps: 60
  };

  for (let i = 0; i < args.length; i++) {
    switch (args[i]) {
      case '--duration':
      case '-d':
        options.duration = parseInt(args[++i], 10);
        break;
      case '--fps':
      case '-f':
        options.targetFps = parseInt(args[++i], 10);
        break;
      case '--output':
      case '-o':
        options.output = args[++i];
        break;
      case '--json':
        options.json = true;
        break;
      case '--fail-on-2ms':
        options.failOn2ms = true;
        break;
