import { chromium, Browser, Page } from 'playwright';
import { writeFileSync } from 'fs';
import { join } from 'path';

interface ValidationOptions {
  duration?: number;
  targetFps?: number;
  outputPath?: string;
  failOn2ms?: boolean;
  failOn5ms?: boolean;
  headless?: boolean;
  port?: number;
}

/**
 * Run hardware timing validation using Playwright
 */
async function runTimingValidation(options: ValidationOptions = {}) {
  const {
    duration = 3000,
    targetFps = 60,
    outputPath,
    failOn2ms = false,
    failOn5ms = false,
    headless = true,
    port = 3000
  } = options;

  let browser: Browser | null = null;
  let exitCode = 0;

  try {
    console.log('🚀 Starting timing validation with Playwright...');

    // Launch browser
    browser = await chromium.launch({
      headless,
      args: [
        '--no-sandbox',
        '--disable-setuid-sandbox',
        '--disable-dev-shm-usage',
        '--disable-accelerated-2d-canvas',
        '--no-first-run',
        '--no-zygote',
        '--disable-gpu' // Disable GPU in CI environments
      ]
    });

    const context = await browser.newContext({
      viewport: { width: 1920, height: 1080 }
    });

    const page = await context.newPage();

    // Set up console logging
    page.on('console', (msg) => {
      if (msg.type() === 'error') {
        console.error('Browser Error:', msg.text());
      }
    });

    // Navigate to validation page
    const url = `http://localhost:${port}/packages/timing/src/browser-runner/timing-validation-runner.html?autorun=true&duration=${duration}&fps=${targetFps}`;
    console.log(`📍 Navigating to: ${url}`);

    await page.goto(url, { waitUntil: 'networkidle' });

    // Wait for validation to complete
    console.log(`⏳ Running validation for ${duration}ms...`);

    const results = await page.waitForFunction(
      () => window.validationResults || window.validationError,
      { timeout: duration + 30000 } // Extra time for setup and processing
    );

    // Get results
    const validationData = await page.evaluate(() => ({
      results: window.validationResults,
      report: window.validationReport,
      error: window.validationError
    }));

    if (validationData.error) {
      console.error('❌ Validation failed:', validationData.error);
      exitCode = 1;
    } else if (validationData.results) {
      console.log('\n✅ Validation completed successfully\n');

      // Display key metrics
      console.log('📊 Key Metrics:');
      console.log(`   Platform: ${validationData.results.deviceCapabilities.platform}`);
      console.log(`   WebGL: ${validationData.results.deviceCapabilities.webGL2Supported ? 'WebGL2' : 
        validationData.results.deviceCapabilities.webGL1Supported ? 'WebGL1' : 'None'}`);
      console.log(`   Frame Rate: ${validationData.results.fpsMetrics.actualFps.toFixed(1)} FPS`);
      console.log(`   Clock Resolution: ${validationData.results.timingPrecision.clockResolution.toFixed(0)}μs`);
      console.log(`   2ms Precision: ${validationData.results.compatibilityMatrix.canRun2msPrecision ? '✅' : '❌'}`);
      console.log(`   5ms Precision: ${validationData.results.compatibilityMatrix.canRun5msPrecision ? '✅' : '❌'}`);

      // Display warnings
      if (validationData.results.compatibilityMatrix.warnings.length > 0) {
        console.log('\n⚠️  Warnings:');
        validationData.results.compatibilityMatrix.warnings.forEach((warning: string) => {
          console.log(`   - ${warning}`);
        });
      }

      // Save results if output path specified
      if (outputPath) {
        const outputData = {
          timestamp: new Date().toISOString(),
          results: validationData.results,
          report: validationData.report
        };
        writeFileSync(outputPath, JSON.stringify(outputData, null, 2));
        console.log(`\n💾 Results saved to: ${outputPath}`);
      }

      // Check failure conditions
      if (failOn2ms && !validationData.results.compatibilityMatrix.canRun2msPrecision) {
        console.error('\n❌ FAIL: 2ms precision not supported');
        exitCode = 1;
      }

      if (failOn5ms && !validationData.results.compatibilityMatrix.canRun5msPrecision) {
        console.error('\n❌ FAIL: 5ms precision not supported');
        exitCode = 1;
      }
    }

    // Take screenshot for CI artifacts
    await page.screenshot({ 
      path: 'timing-validation-screenshot.png',
      fullPage: true 
    });
    console.log('📸 Screenshot saved: timing-validation-screenshot.png');

  } catch (error) {
    console.error('❌ Unexpected error:', error);
    exitCode = 1;
  } finally {
    if (browser) {
      await browser.close();
    }
  }

  return exitCode;
}

// CLI interface
if (require.main === module) {
  const args = process.argv.slice(2);
  const options: ValidationOptions = {};

  for (let i = 0; i < args.length; i++) {
    switch (args[i]) {
      case '--duration':
        options.duration = parseInt(args[++i], 10);
        break;
      case '--fps':
        options.targetFps = parseInt(args[++i], 10);
        break;
      case '--output':
        options.outputPath = args[++i];
        break;
      case '--fail-on-2ms':
        options.failOn2ms = true;
        break;
      case '--fail-on-5ms':
        options.failOn5ms = true;
        break;
      case '--headed':
        options.headless = false;
        break;
      case '--port':
        options.port = parseInt(args[++i], 10);
        break;
      case '--help':
        console.log(`
Hardware Timing Validation CI Runner

Usage: npx ts-node validate-timing-ci.ts [options]

Options:
  --duration <ms>      Test duration in milliseconds (default: 3000)
  --fps <fps>          Target frame rate (default: 60)
  --output <path>      Save JSON results to file
  --fail-on-2ms        Exit with error if 2ms precision not supported
  --fail-on-5ms        Exit with error if 5ms precision not supported
  --headed             Run browser in headed mode (default: headless)
  --port <port>        Dev server port (default: 3000)
  --help               Show this help

Example:
  npx ts-node validate-timing-ci.ts --duration 5000 --fail-on-5ms --output results.json
`);
        process.exit(0);
    }
  }

  runTimingValidation(options).then(exitCode => {
    process.exit(exitCode);
  });
}

export { runTimingValidation };

