content.content:
     1→import * as PIXI from 'pixi.js';
     2→import type { TimelineContext } from '../core/Timeline.js';
     3→import { BaseStimulus } from './BaseStimulus.js';
     4→import { PerformanceMonitor } from '../validation/PerformanceMonitor.js';
     5→
     6→export interface RendererOptions {
     7→  width?: number;
     8→  height?: number;
     9→  backgroundColor?: number | string;
    10→  antialias?: boolean;
    11→  resolution?: number;
    12→  powerPreference?: 'high-performance' | 'low-power' | 'default';
    13→  preserveDrawingBuffer?: boolean;
    14→  preferWebGL2?: boolean;
    15→  enableFallback?: boolean;
    16→}
    17→
    18→export interface RendererCapabilities {
    19→  webGL2: boolean;
    20→  webGL1: boolean;
    21→  canvas2D: boolean;
    22→  maxTextureSize: number;
    23→  maxRenderBufferSize: number;
    24→  supportedExtensions: string[];
    25→  renderer: 'webgl2' | 'webgl' | 'canvas' | 'unknown';
    26→}
    27→
    28→export class EnhancedStimulusRenderer {
    29→  private static instance: EnhancedStimulusRenderer;
    30→  private app?: PIXI.Application;
    31→  private activeStimuli: Map<string, BaseStimulus> = new Map();
    32→  private isInitialized = false;
    33→  private capabilities: RendererCapabilities;
    34→  private performanceMonitor?: PerformanceMonitor;
    35→  private canvas2DFallback?: HTMLCanvasElement;
    36→  private canvas2DContext?: CanvasRenderingContext2D;
    37→  private useFallback = false;
    38→
    39→  private constructor() {
    40→    this.capabilities = this.detectCapabilities();
    41→  }
    42→
    43→  static getInstance(): EnhancedStimulusRenderer {
    44→    if (!EnhancedStimulusRenderer.instance) {
    45→      EnhancedStimulusRenderer.instance = new EnhancedStimulusRenderer();
    46→    }
    47→    return EnhancedStimulusRenderer.instance;
    48→  }
    49→
    50→  private detectCapabilities(): RendererCapabilities {
    51→    const canvas = document.createElement('canvas');
    52→    
    53→    // Check WebGL2
    54→    const gl2 = canvas.getContext('webgl2');
    55→    const hasWebGL2 = gl2 !== null;
    56→    
    57→    // Check WebGL1
    58→    const gl1 = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
    59→    const hasWebGL1 = gl1 !== null;
    60→    
    61→    // Check Canvas2D
    62→    const ctx2d = canvas.getContext('2d');
    63→    const hasCanvas2D = ctx2d !== null;
    64→
    65→    // Get capabilities from available context
    66→    let maxTextureSize = 4096;
    67→    let maxRenderBufferSize = 4096;
    68→    let supportedExtensions: string[] = [];
    69→    let renderer: RendererCapabilities['renderer'] = 'unknown';
    70→
    71→    if (gl2) {
    72→      maxTextureSize = gl2.getParameter(gl2.MAX_TEXTURE_SIZE);
    73→      maxRenderBufferSize = gl2.getParameter(gl2.MAX_RENDERBUFFER_SIZE);
    74→      supportedExtensions = gl2.getSupportedExtensions() || [];
    75→      renderer = 'webgl2';
    76→    } else if (gl1) {
    77→      maxTextureSize = (gl1 as WebGLRenderingContext).getParameter((gl1 as WebGLRenderingContext).MAX_TEXTURE_SIZE);
    78→      maxRenderBufferSize = (gl1 as WebGLRenderingContext).getParameter((gl1 as WebGLRenderingContext).MAX_RENDERBUFFER_SIZE);
    79→      supportedExtensions = (gl1 as WebGLRenderingContext).getSupportedExtensions() || [];
    80→      renderer = 'webgl';
    81→    } else if (hasCanvas2D) {
    82→      renderer = 'canvas';
    83→    }
    84→
    85→    return {
    86→      webGL2: hasWebGL2,
    87→      webGL1: hasWebGL1,
    88→      canvas2D: hasCanvas2D,
    89→      maxTextureSize,
    90→      maxRenderBufferSize,
    91→      supportedExtensions,
    92→      renderer
    93→    };
    94→  }
    95→
    96→  getCapabilities(): RendererCapabilities {
    97→    return { ...this.capabilities };
    98→  }
    99→
   100→  async initialize(options: RendererOptions = {}): Promise<void> {
   101→    if (this.isInitialized) {
   102→      return;
   103→    }
   104→
   105→    // Log capabilities
   106→    console.log('🎮 Renderer Capabilities:', this.capabilities);
   107→
   108→    // Determine renderer type
   109→    const preferWebGL2 = options.preferWebGL2 !== false;
   110→    const enableFallback = options.enableFallback !== false;
   111→
   112→    // Try to use WebGL2/WebGL1 with PIXI
   113→    if ((preferWebGL2 && this.capabilities.webGL2) || (!preferWebGL2 && this.capabilities.webGL1)) {
   114→      try {
   115→        await this.initializePixi(options);
   116→        console.log('✅ Initialized with', this.capabilities.renderer.toUpperCase());
   117→      } catch (error) {
   118→        console.warn('⚠️ PIXI initialization failed:', error);
   119→        
   120→        if (enableFallback && this.capabilities.canvas2D) {
   121→          console.log('🔄 Falling back to Canvas2D renderer...');
   122→          this.initializeCanvas2DFallback(options);
   123→        } else {
   124→          throw new Error('No suitable renderer available');
   125→        }
   126→      }
