import * as PIXI from 'pixi.js';
import type { TimelineContext } from '../core/Timeline.js';
import { BaseStimulus } from './BaseStimulus.js';
import { PerformanceMonitor } from '../validation/PerformanceMonitor.js';

export interface RendererOptions {
  width?: number;
  height?: number;
  backgroundColor?: number | string;
  antialias?: boolean;
  resolution?: number;
  powerPreference?: 'high-performance' | 'low-power' | 'default';
  preserveDrawingBuffer?: boolean;
  preferWebGL2?: boolean;
  enableFallback?: boolean;
}

export interface RendererCapabilities {
  webGL2: boolean;
  webGL1: boolean;
  canvas2D: boolean;
  maxTextureSize: number;
  maxRenderBufferSize: number;
  supportedExtensions: string[];
  renderer: 'webgl2' | 'webgl' | 'canvas' | 'unknown';
}

export class EnhancedStimulusRenderer {
  private static instance: EnhancedStimulusRenderer;
  private app?: PIXI.Application;
  private activeStimuli: Map<string, BaseStimulus> = new Map();
  private isInitialized = false;
  private capabilities: RendererCapabilities;
  private performanceMonitor?: PerformanceMonitor;
  private canvas2DFallback?: HTMLCanvasElement;
  private canvas2DContext?: CanvasRenderingContext2D;
  private useFallback = false;

  private constructor() {
    this.capabilities = this.detectCapabilities();
  }

  static getInstance(): EnhancedStimulusRenderer {
    if (!EnhancedStimulusRenderer.instance) {
      EnhancedStimulusRenderer.instance = new EnhancedStimulusRenderer();
    }
    return EnhancedStimulusRenderer.instance;
  }

  private detectCapabilities(): RendererCapabilities {
    const canvas = document.createElement('canvas');

    // Check WebGL2
    const gl2 = canvas.getContext('webgl2');
    const hasWebGL2 = gl2 !== null;

    // Check WebGL1
    const gl1 = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
    const hasWebGL1 = gl1 !== null;

    // Check Canvas2D
    const ctx2d = canvas.getContext('2d');
    const hasCanvas2D = ctx2d !== null;

    // Get capabilities from available context
    let maxTextureSize = 4096;
    let maxRenderBufferSize = 4096;
    let supportedExtensions: string[] = [];
    let renderer: RendererCapabilities['renderer'] = 'unknown';

    if (gl2) {
      maxTextureSize = gl2.getParameter(gl2.MAX_TEXTURE_SIZE);
      maxRenderBufferSize = gl2.getParameter(gl2.MAX_RENDERBUFFER_SIZE);
      supportedExtensions = gl2.getSupportedExtensions() || [];
      renderer = 'webgl2';
    } else if (gl1) {
      maxTextureSize = (gl1 as WebGLRenderingContext).getParameter((gl1 as WebGLRenderingContext).MAX_TEXTURE_SIZE);
      maxRenderBufferSize = (gl1 as WebGLRenderingContext).getParameter((gl1 as WebGLRenderingContext).MAX_RENDERBUFFER_SIZE);
      supportedExtensions = (gl1 as WebGLRenderingContext).getSupportedExtensions() || [];
      renderer = 'webgl';
    } else if (hasCanvas2D) {
      renderer = 'canvas';
    }

    return {
      webGL2: hasWebGL2,
      webGL1: hasWebGL1,
      canvas2D: hasCanvas2D,
      maxTextureSize,
      maxRenderBufferSize,
      supportedExtensions,
      renderer
    };
  }

  getCapabilities(): RendererCapabilities {
    return { ...this.capabilities };
  }

  async initialize(options: RendererOptions = {}): Promise<void> {
    if (this.isInitialized) {
      return;
    }

    // Log capabilities
    console.log('🎮 Renderer Capabilities:', this.capabilities);

    // Determine renderer type
    const preferWebGL2 = options.preferWebGL2 !== false;
    const enableFallback = options.enableFallback !== false;

    // Try to use WebGL2/WebGL1 with PIXI
    if ((preferWebGL2 && this.capabilities.webGL2) || (!preferWebGL2 && this.capabilities.webGL1)) {
      try {
        await this.initializePixi(options);
        console.log('✅ Initialized with', this.capabilities.renderer.toUpperCase());
      } catch (error) {
        console.warn('⚠️ PIXI initialization failed:', error);

        if (enableFallback && this.capabilities.canvas2D) {
          console.log('🔄 Falling back to Canvas2D renderer...');
          this.initializeCanvas2DFallback(options);
        } else {
          throw new Error('No suitable renderer available');
        }
      }
    } else if (enableFallback && this.capabilities.canvas2D) {
      console.log('📐 Using Canvas2D fallback renderer');
      this.initializeCanvas2DFallback(options);
    } else {
      throw new Error('No suitable renderer available. WebGL is required.');
    }

    // Initialize performance monitor
    if (options.powerPreference === 'high-performance') {
      this.performanceMonitor = new PerformanceMonitor({
        minFPS: 55,
        maxFrameTime: 20,
        maxHeapUsage: 500
      });
      this.performanceMonitor.start();
    }

    this.isInitialized = true;
  }

  private async initializePixi(options: RendererOptions): Promise<void> {
    // Parse background color
    let bgColor = 0x000000;
    if (options.backgroundColor !== undefined) {
      if (typeof options.backgroundColor === 'string') {
        bgColor = parseInt(options.backgroundColor.replace('#', ''), 16);
      } else {
        bgColor = options.backgroundColor;
      }
    }

    // Create PIXI application with appropriate settings
    this.app = new PIXI.Application();

    await this.app.init({
      width: options.width || window.innerWidth,
      height: options.height || window.innerHeight,
      antialias: options.antialias !== false,
      resolution: options.resolution || window.devicePixelRatio || 1,
      autoDensity: true,
      backgroundColor: bgColor,
      powerPreference: options.powerPreference || 'high-performance',
      preserveDrawingBuffer: options.preserveDrawingBuffer || false,
      preferWebGPU: false, // Ensure WebGL is used
      hello: true // Log renderer info
    });

    // Configure for psychology experiments
    this.app.stage.sortableChildren = true;
    this.app.stage.eventMode = 'static';

    // Style canvas
    this.app.canvas.id = 'psyforge-renderer';
    this.app.canvas.style.position = 'fixed';
    this.app.canvas.style.top = '0';
    this.app.canvas.style.left = '0';
    this.app.canvas.style.width = '100%';
    this.app.canvas.style.height = '100%';
    this.app.canvas.style.zIndex = '1000';

    // Add to document
    document.body.appendChild(this.app.canvas);

    // Handle window resize
    window.addEventListener('resize', this.handleResize.bind(this));

    // Store globally for BaseStimulus access
    (window as any).__psyforgePixiApp = this.app;
  }

  private initializeCanvas2DFallback(options: RendererOptions): void {
    this.useFallback = true;

    // Create canvas element
    this.canvas2DFallback = document.createElement('canvas');
    this.canvas2DFallback.id = 'psyforge-renderer-fallback';
    this.canvas2DFallback.width = options.width || window.innerWidth;
    this.canvas2DFallback.height = options.height || window.innerHeight;

    // Style canvas
    this.canvas2DFallback.style.position = 'fixed';
    this.canvas2DFallback.style.top = '0';
    this.canvas2DFallback.style.left = '0';
    this.canvas2DFallback.style.width = '100%';
    this.canvas2DFallback.style.height = '100%';
    this.canvas2DFallback.style.zIndex = '1000';

    // Get 2D context
    this.canvas2DContext = this.canvas2DFallback.getContext('2d');
    if (!this.canvas2DContext) {
      throw new Error('Failed to get 2D context');
    }

    // Set background
    if (options.backgroundColor) {
      const bgColor = typeof options.backgroundColor === 'string' 
        ? options.backgroundColor 
        : `#${options.backgroundColor.toString(16).padStart(6, '0')}`;
      this.canvas2DContext.fillStyle = bgColor;
      this.canvas2DContext.fillRect(0, 0, this.canvas2DFallback.width, this.canvas2DFallback.height);
    }

    // Add to document
    document.body.appendChild(this.canvas2DFallback);

    // Handle window resize
    window.addEventListener('resize', this.handleResizeFallback.bind(this));

    // Warn about reduced functionality
    console.warn('⚠️ Using Canvas2D fallback. Some features may be limited:');
    console.warn('  - No WebGL effects (blur, filters)');
    console.warn('  - Reduced performance for complex scenes');
    console.warn('  - Limited text rendering options');
  }

  private handleResize(): void {
    if (this.app) {
      this.app.renderer.resize(window.innerWidth, window.innerHeight);
    }
  }

  private handleResizeFallback(): void {
    if (this.canvas2DFallback) {
      this.canvas2DFallback.width = window.innerWidth;
      this.canvas2DFallback.height = window.innerHeight;
    }
  }

  async presentStimulus(stimulus: BaseStimulus, context: TimelineContext): Promise<void> {
    if (!this.isInitialized) {
      await this.initialize();
    }

    if (this.useFallback) {
      // Handle Canvas2D fallback presentation
      await this.presentStimulusFallback(stimulus, context);
    } else {
      // Use PIXI presentation
      await stimulus.initialize(context);
      await stimulus.present(context);
    }

    this.activeStimuli.set((stimulus as any).id, stimulus);
  }

  private async presentStimulusFallback(stimulus: BaseStimulus, context: TimelineContext): Promise<void> {
    if (!this.canvas2DContext) return;

    // Clear canvas
    this.canvas2DContext.clearRect(0, 0, this.canvas2DFallback!.width, this.canvas2DFallback!.height);

    // Basic stimulus rendering for Canvas2D
    const stimulusType = stimulus.constructor.name;

    if (stimulusType === 'TextStimulusPixi') {
      // Render text
      const textStimulus = stimulus as any;
      this.canvas2DContext.font = `${textStimulus.fontSize}px ${textStimulus.fontFamily}`;
      this.canvas2DContext.fillStyle = textStimulus.color;
      this.canvas2DContext.textAlign = 'center';
      this.canvas2DContext.textBaseline = 'middle';
      this.canvas2DContext.fillText(
        textStimulus.text,
        this.canvas2DFallback!.width / 2,
        this.canvas2DFallback!.height / 2
      );
    } else if (stimulusType === 'ImageStimulusPixi') {
      // Render image
      const imageStimulus = stimulus as any;
      const img = new Image();
      img.src = imageStimulus.src;

      await new Promise((resolve) => {
        img.onload = () => {
          this.canvas2DContext!.drawImage(
            img,
            (this.canvas2DFallback!.width - img.width) / 2,
            (this.canvas2DFallback!.height - img.height) / 2
          );
          resolve(null);
        };
      });
    } else if (stimulusType === 'ShapeStimulusPixi') {
      // Render basic shapes
      const shapeStimulus = stimulus as any;
      this.canvas2DContext.fillStyle = shapeStimulus.fillColor;

      if (shapeStimulus.shapeType === 'rectangle') {
        this.canvas2DContext.fillRect(
          (this.canvas2DFallback!.width - shapeStimulus.width) / 2,
          (this.canvas2DFallback!.height - shapeStimulus.height) / 2,
          shapeStimulus.width,
          shapeStimulus.height
        );
      } else if (shapeStimulus.shapeType === 'circle') {
        this.canvas2DContext.beginPath();
        this.canvas2DContext.arc(
          this.canvas2DFallback!.width / 2,
          this.canvas2DFallback!.height / 2,
          shapeStimulus.radius,
          0,
          Math.PI * 2
        );
        this.canvas2DContext.fill();
      }
    }
  }

  async removeStimulus(stimulus: BaseStimulus, context: TimelineContext): Promise<void> {
    if (!this.useFallback) {
      await stimulus.remove(context);
    } else {
      // Clear canvas for fallback
      if (this.canvas2DContext && this.canvas2DFallback) {
        this.canvas2DContext.clearRect(0, 0, this.canvas2DFallback.width, this.canvas2DFallback.height);
      }
    }

    this.activeStimuli.delete((stimulus as any).id);
  }

  async clearAll(context: TimelineContext): Promise<void> {
    if (!this.useFallback) {
      // PIXI clear
      const removalPromises = Array.from(this.activeStimuli.values()).map(
        stimulus => stimulus.remove(context)
      );
      await Promise.all(removalPromises);

      if (this.app) {
        this.app.stage.removeChildren();
      }
    } else {
      // Canvas2D clear
      if (this.canvas2DContext && this.canvas2DFallback) {
        this.canvas2DContext.clearRect(0, 0, this.canvas2DFallback.width, this.canvas2DFallback.height);
      }
    }

    this.activeStimuli.clear();
  }

  getApp(): PIXI.Application | undefined {
    return this.app;
  }

  getCanvas(): HTMLCanvasElement {
    if (this.useFallback) {
      return this.canvas2DFallback!;
    }
    return this.app?.canvas || document.createElement('canvas');
  }

  isUsingFallback(): boolean {
    return this.useFallback;
  }

  getPerformanceMetrics(): any {
    if (!this.performanceMonitor) return null;

    return {
      current: this.performanceMonitor.getLatestMetrics(),
      average: this.performanceMonitor.getAverageMetrics()
    };
  }

  // Performance monitoring
  getFPS(): number {
    if (this.app) {
      return this.app.ticker.FPS;
    }
    // Estimate FPS for Canvas2D fallback
    return 60; // Assume 60fps for fallback
  }

  getMemoryUsage(): { textureCount: number; textureMemory: number } {
    if (!this.app) {
      return { textureCount: 0, textureMemory: 0 };
    }

    const textures = PIXI.utils.TextureCache;
    let textureCount = 0;
    let textureMemory = 0;

    for (const key in textures) {
      const texture = textures[key];
      if (texture && texture.source) {
        textureCount++;
        textureMemory += texture.source.width * texture.source.height * 4;
      }
    }

    return { textureCount, textureMemory };
  }

  // Utility methods
  setBackgroundColor(color: number | string): void {
    if (!this.useFallback && this.app) {
      if (typeof color === 'string') {
        this.app.renderer.background.color = parseInt(color.replace('#', ''), 16);
      } else {
        this.app.renderer.background.color = color;
      }
    } else if (this.canvas2DContext && this.canvas2DFallback) {
      const bgColor = typeof color === 'string' 
        ? color 
        : `#${color.toString(16).padStart(6, '0')}`;
      this.canvas2DContext.fillStyle = bgColor;
      this.canvas2DContext.fillRect(0, 0, this.canvas2DFallback.width, this.canvas2DFallback.height);
    }
  }

  setCursorVisible(visible: boolean): void {
    const canvas = this.getCanvas();
    canvas.style.cursor = visible ? 'auto' : 'none';
  }

  async takeScreenshot(): Promise<string> {
    if (!this.useFallback && this.app) {
      this.app.render();
      const dataUrl = await this.app.renderer.extract.base64(this.app.stage);
      return dataUrl;
    } else if (this.canvas2DFallback) {
      return this.canvas2DFallback.toDataURL();
    }

    throw new Error('No renderer available for screenshot');
  }

  // Cleanup
  destroy(): void {
    if (this.performanceMonitor) {
      this.performanceMonitor.stop();
    }

    window.removeEventListener('resize', this.handleResize.bind(this));
    window.removeEventListener('resize', this.handleResizeFallback.bind(this));

    this.activeStimuli.clear();

    if (this.app) {
      this.app.destroy(true, { children: true, texture: true });
      delete (window as any).__psyforgePixiApp;
    }

    if (this.canvas2DFallback && this.canvas2DFallback.parentNode) {
      this.canvas2DFallback.parentNode.removeChild(this.canvas2DFallback);
    }

    this.isInitialized = false;
    this.useFallback = false;
  }
}

