import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { EnhancedStimulusRenderer } from '../EnhancedStimulusRenderer';
import { BaseStimulus } from '../BaseStimulus';
import { TimelineContext } from '../../core/Timeline';

describe('WebGL Feature Detection and Fallback', () => {
  let renderer: EnhancedStimulusRenderer;
  let originalGetContext: any;

  beforeEach(() => {
    // Clean up any existing singleton
    (EnhancedStimulusRenderer as any).instance = null;
    renderer = EnhancedStimulusRenderer.getInstance();

    // Store original getContext
    originalGetContext = HTMLCanvasElement.prototype.getContext;
  });

  afterEach(() => {
    renderer.destroy();
    // Restore original getContext
    HTMLCanvasElement.prototype.getContext = originalGetContext;
  });

  describe('Capability Detection', () => {
    it('should detect WebGL2 support when available', () => {
      const mockWebGL2Context = {
        getParameter: vi.fn((param: number) => {
          if (param === 0x0D33) return 8192; // MAX_TEXTURE_SIZE
          if (param === 0x84E8) return 8192; // MAX_RENDERBUFFER_SIZE
          return 0;
        }),
        getSupportedExtensions: vi.fn(() => ['EXT_color_buffer_float', 'OES_texture_float'])
      };

      HTMLCanvasElement.prototype.getContext = vi.fn((type: string) => {
        if (type === 'webgl2') return mockWebGL2Context;
        if (type === '2d') return {};
        return null;
      });

      renderer = EnhancedStimulusRenderer.getInstance();
      const capabilities = renderer.getCapabilities();

      expect(capabilities.webGL2).toBe(true);
      expect(capabilities.renderer).toBe('webgl2');
      expect(capabilities.maxTextureSize).toBe(8192);
      expect(capabilities.supportedExtensions).toContain('EXT_color_buffer_float');
    });

    it('should fall back to WebGL1 when WebGL2 is not available', () => {
      const mockWebGL1Context = {
        getParameter: vi.fn((param: number) => {
          if (param === 0x0D33) return 4096; // MAX_TEXTURE_SIZE
          if (param === 0x84E8) return 4096; // MAX_RENDERBUFFER_SIZE
          return 0;
        }),
        getSupportedExtensions: vi.fn(() => ['OES_texture_float'])
      };

      HTMLCanvasElement.prototype.getContext = vi.fn((type: string) => {
        if (type === 'webgl2') return null;
        if (type === 'webgl' || type === 'experimental-webgl') return mockWebGL1Context;
        if (type === '2d') return {};
        return null;
      });

      renderer = EnhancedStimulusRenderer.getInstance();
      const capabilities = renderer.getCapabilities();

      expect(capabilities.webGL2).toBe(false);
      expect(capabilities.webGL1).toBe(true);
      expect(capabilities.renderer).toBe('webgl');
      expect(capabilities.maxTextureSize).toBe(4096);
    });

    it('should detect Canvas2D as last resort', () => {
      HTMLCanvasElement.prototype.getContext = vi.fn((type: string) => {
        if (type === '2d') return {};
        return null;
      });

      renderer = EnhancedStimulusRenderer.getInstance();
      const capabilities = renderer.getCapabilities();

      expect(capabilities.webGL2).toBe(false);
      expect(capabilities.webGL1).toBe(false);
      expect(capabilities.canvas2D).toBe(true);
      expect(capabilities.renderer).toBe('canvas');
    });

    it('should report no renderer when all contexts fail', () => {
      HTMLCanvasElement.prototype.getContext = vi.fn(() => null);

      renderer = EnhancedStimulusRenderer.getInstance();
      const capabilities = renderer.getCapabilities();

      expect(capabilities.webGL2).toBe(false);
      expect(capabilities.webGL1).toBe(false);
      expect(capabilities.canvas2D).toBe(false);
      expect(capabilities.renderer).toBe('unknown');
    });
  });

  describe('Fallback Initialization', () => {
    it('should use Canvas2D fallback when WebGL is unavailable', async () => {
      // Mock only Canvas2D available
      HTMLCanvasElement.prototype.getContext = vi.fn((type: string) => {
        if (type === '2d') {
          return {
            fillRect: vi.fn(),
            clearRect: vi.fn(),
            fillText: vi.fn(),
            drawImage: vi.fn(),
            beginPath: vi.fn(),
            arc: vi.fn(),
            fill: vi.fn()
          };
        }
        return null;
      });

      const consoleWarnSpy = vi.spyOn(console, 'warn');

      renderer = EnhancedStimulusRenderer.getInstance();
      await renderer.initialize({ enableFallback: true });

      expect(renderer.isUsingFallback()).toBe(true);
      expect(consoleWarnSpy).toHaveBeenCalledWith(
        expect.stringContaining('Using Canvas2D fallback')
      );
    });

    it('should throw error when no renderer is available and fallback disabled', async () => {
      HTMLCanvasElement.prototype.getContext = vi.fn(() => null);

      renderer = EnhancedStimulusRenderer.getInstance();

      await expect(
        renderer.initialize({ enableFallback: false })
      ).rejects.toThrow('No suitable renderer available');
    });

    it('should prefer WebGL2 when available', async () => {
      const mockApp = {
        init: vi.fn().mockResolvedValue(undefined),
        stage: { sortableChildren: true, eventMode: 'static' },
        canvas: document.createElement('canvas'),
        ticker: { FPS: 60 }
      };

      // Mock PIXI
      vi.doMock('pixi.js', () => ({
        Application: vi.fn(() => mockApp)
      }));

      HTMLCanvasElement.prototype.getContext = vi.fn((type: string) => {
        if (type === 'webgl2') return { getParameter: vi.fn(), getSupportedExtensions: vi.fn(() => []) };
        if (type === '2d') return {};
        return null;
      });

      renderer = EnhancedStimulusRenderer.getInstance();
      await renderer.initialize({ preferWebGL2: true });

      const capabilities = renderer.getCapabilities();
      expect(capabilities.renderer).toBe('webgl2');
    });
  });

  describe('Canvas2D Fallback Rendering', () => {
    let mockContext: any;
    let mockCanvas: HTMLCanvasElement;

    beforeEach(() => {
      mockCanvas = {
        width: 800,
        height: 600,
        style: {},
        getContext: vi.fn()
      } as any;

      mockContext = {
        fillRect: vi.fn(),
        clearRect: vi.fn(),
        fillText: vi.fn(),
        drawImage: vi.fn(),
        beginPath: vi.fn(),
        arc: vi.fn(),
        fill: vi.fn(),
        font: '',
        fillStyle: '',
        textAlign: '',
        textBaseline: ''
      };

      document.createElement = vi.fn(() => mockCanvas);
      mockCanvas.getContext = vi.fn(() => mockContext);

      HTMLCanvasElement.prototype.getContext = vi.fn((type: string) => {
        if (type === '2d') return mockContext;
        return null;
      });
    });

    it('should render text stimulus in fallback mode', async () => {
      renderer = EnhancedStimulusRenderer.getInstance();
      await renderer.initialize({ enableFallback: true });

      const textStimulus = {
        constructor: { name: 'TextStimulusPixi' },
        id: 'text-1',
        text: 'Hello World',
        fontSize: 24,
        fontFamily: 'Arial',
        color: '#FFFFFF',
        initialize: vi.fn(),
        present: vi.fn(),
        remove: vi.fn()
      } as any;

      const context = {} as TimelineContext;
      await renderer.presentStimulus(textStimulus, context);

      expect(mockContext.fillText).toHaveBeenCalledWith(
        'Hello World',
        400, // center X
        300  // center Y
      );
      expect(mockContext.font).toBe('24px Arial');
      expect(mockContext.fillStyle).toBe('#FFFFFF');
    });

    it('should render shape stimulus in fallback mode', async () => {
      renderer = EnhancedStimulusRenderer.getInstance();
      await renderer.initialize({ enableFallback: true });

      const rectStimulus = {
        constructor: { name: 'ShapeStimulusPixi' },
        id: 'rect-1',
        shapeType: 'rectangle',
        width: 100,
        height: 50,
        fillColor: '#FF0000',
        initialize: vi.fn(),
        present: vi.fn(),
        remove: vi.fn()
      } as any;

      const context = {} as TimelineContext;
      await renderer.presentStimulus(rectStimulus, context);

      expect(mockContext.fillRect).toHaveBeenCalledWith(
        350, // center X - width/2
        275, // center Y - height/2
        100,
        50
      );
      expect(mockContext.fillStyle).toBe('#FF0000');
    });

    it('should handle circle shapes in fallback mode', async () => {
      renderer = EnhancedStimulusRenderer.getInstance();
      await renderer.initialize({ enableFallback: true });

      const circleStimulus = {
        constructor: { name: 'ShapeStimulusPixi' },
        id: 'circle-1',
        shapeType: 'circle',
        radius: 30,
        fillColor: '#00FF00',
        initialize: vi.fn(),
        present: vi.fn(),
        remove: vi.fn()
      } as any;

      const context = {} as TimelineContext;
      await renderer.presentStimulus(circleStimulus, context);

      expect(mockContext.beginPath).toHaveBeenCalled();
      expect(mockContext.arc).toHaveBeenCalledWith(
        400, // center X
        300, // center Y
        30,  // radius
        0,
        Math.PI * 2
      );
      expect(mockContext.fill).toHaveBeenCalled();
    });

    it('should clear canvas when removing stimulus in fallback mode', async () => {
      renderer = EnhancedStimulusRenderer.getInstance();
      await renderer.initialize({ enableFallback: true });

      const stimulus = {
        id: 'test-1',
        remove: vi.fn()
      } as any;

      const context = {} as TimelineContext;
      await renderer.removeStimulus(stimulus, context);

      expect(mockContext.clearRect).toHaveBeenCalledWith(0, 0, 800, 600);
    });
  });

  describe('Performance Warnings', () => {
    it('should warn about Canvas2D limitations', async () => {
      HTMLCanvasElement.prototype.getContext = vi.fn((type: string) => {
        if (type === '2d') return { fillRect: vi.fn(), clearRect: vi.fn() };
        return null;
      });

      const consoleWarnSpy = vi.spyOn(console, 'warn');

      renderer = EnhancedStimulusRenderer.getInstance();
      await renderer.initialize();

      expect(consoleWarnSpy).toHaveBeenCalledWith(
        expect.stringContaining('No WebGL effects')
      );
      expect(consoleWarnSpy).toHaveBeenCalledWith(
        expect.stringContaining('Reduced performance')
      );
      expect(consoleWarnSpy).toHaveBeenCalledWith(
        expect.stringContaining('Limited text rendering')
      );
    });
  });

  describe('Feature Degradation', () => {
    it('should handle screenshot in fallback mode', async () => {
      const mockCanvas = {
        toDataURL: vi.fn(() => 'data:image/png;base64,test'),
        width: 800,
        height: 600,
        style: {},
        getContext: vi.fn(() => ({
          fillRect: vi.fn(),
          clearRect: vi.fn()
        }))
      } as any;

      document.createElement = vi.fn(() => mockCanvas);
      HTMLCanvasElement.prototype.getContext = vi.fn((type: string) => {
        if (type === '2d') return {};
        return null;
      });

      renderer = EnhancedStimulusRenderer.getInstance();
      await renderer.initialize();

      const screenshot = await renderer.takeScreenshot();
      expect(screenshot).toBe('data:image/png;base64,test');
    });

    it('should provide estimated FPS in fallback mode', async () => {
      HTMLCanvasElement.prototype.getContext = vi.fn((type: string) => {
        if (type === '2d') return { fillRect: vi.fn(), clearRect: vi.fn() };
        return null;
      });

      renderer = EnhancedStimulusRenderer.getInstance();
      await renderer.initialize();

      const fps = renderer.getFPS();
      expect(fps).toBe(60); // Assumed 60fps for fallback
    });
  });
});

