import { EnhancedStimulusRenderer, RendererCapabilities } from '../stimuli/EnhancedStimulusRenderer';

export interface CapabilityWarning {
  level: 'info' | 'warning' | 'error';
  category: 'renderer' | 'performance' | 'feature' | 'compatibility';
  message: string;
  details?: string;
  mitigation?: string;
}

export class CapabilityChecker {
  private renderer: EnhancedStimulusRenderer;
  private warnings: CapabilityWarning[] = [];

  constructor() {
    this.renderer = EnhancedStimulusRenderer.getInstance();
  }

  /**
   * Check system capabilities and generate warnings
   */
  checkCapabilities(): CapabilityWarning[] {
    this.warnings = [];
    const capabilities = this.renderer.getCapabilities();

    // Check renderer capabilities
    this.checkRendererCapabilities(capabilities);

    // Check performance capabilities
    this.checkPerformanceCapabilities();

    // Check browser compatibility
    this.checkBrowserCompatibility();

    // Check timing precision capabilities
    this.checkTimingCapabilities();

    return this.warnings;
  }

  private checkRendererCapabilities(capabilities: RendererCapabilities): void {
    // No WebGL support at all
    if (!capabilities.webGL2 && !capabilities.webGL1) {
      this.warnings.push({
        level: 'error',
        category: 'renderer',
        message: 'No WebGL support detected',
        details: 'Your browser/device does not support WebGL. Performance will be severely limited.',
        mitigation: 'Use a modern browser with WebGL support or enable hardware acceleration.'
      });
    } 
    // Only WebGL1 available
    else if (!capabilities.webGL2 && capabilities.webGL1) {
      this.warnings.push({
        level: 'warning',
        category: 'renderer',
        message: 'Limited to WebGL1',
        details: 'WebGL2 is not available. Some advanced rendering features may be unavailable.',
        mitigation: 'Update your browser or graphics drivers for WebGL2 support.'
      });
    }

    // Check texture size limits
    if (capabilities.maxTextureSize < 4096) {
      this.warnings.push({
        level: 'warning',
        category: 'renderer',
        message: 'Low texture size limit',
        details: `Maximum texture size is ${capabilities.maxTextureSize}px. Large images may not display correctly.`,
        mitigation: 'Use smaller stimulus images or upgrade graphics hardware.'
      });
    }

    // Check for important WebGL extensions
    const criticalExtensions = [
      'OES_texture_float',
      'OES_texture_float_linear',
      'EXT_color_buffer_float'
    ];

    const missingExtensions = criticalExtensions.filter(
      ext => !capabilities.supportedExtensions.includes(ext)
    );

    if (missingExtensions.length > 0) {
      this.warnings.push({
        level: 'info',
        category: 'feature',
        message: 'Some WebGL extensions unavailable',
        details: `Missing extensions: ${missingExtensions.join(', ')}. Some advanced effects may be limited.`
      });
    }
  }

  private checkPerformanceCapabilities(): void {
    // Check hardware concurrency
    const cores = navigator.hardwareConcurrency || 1;
    if (cores < 4) {
      this.warnings.push({
        level: 'warning',
        category: 'performance',
        message: 'Low CPU core count',
        details: `Only ${cores} CPU cores detected. Complex experiments may have performance issues.`,
        mitigation: 'Close other applications during experiments or use a more powerful computer.'
      });
    }

    // Check device memory if available
    const deviceMemory = (navigator as any).deviceMemory;
    if (deviceMemory && deviceMemory < 4) {
      this.warnings.push({
        level: 'warning',
        category: 'performance',
        message: 'Low device memory',
        details: `Only ${deviceMemory}GB RAM detected. Large experiments may run out of memory.`,
        mitigation: 'Close other applications or use a device with more memory.'
      });
    }

    // Check if running on battery (mobile/laptop)
    if ('getBattery' in navigator) {
      (navigator as any).getBattery().then((battery: any) => {
        if (!battery.charging && battery.level < 0.5) {
          this.warnings.push({
            level: 'info',
            category: 'performance',
            message: 'Running on battery power',
            details: 'Performance may be reduced when running on battery.',
            mitigation: 'Connect to power for optimal performance during experiments.'
          });
        }
      });
    }
  }

  private checkBrowserCompatibility(): void {
    const userAgent = navigator.userAgent.toLowerCase();

    // Check for old browsers
    if (userAgent.includes('msie') || userAgent.includes('trident')) {
      this.warnings.push({
        level: 'error',
        category: 'compatibility',
        message: 'Internet Explorer detected',
        details: 'Internet Explorer is not supported. Please use a modern browser.',
        mitigation: 'Use Chrome, Firefox, Safari, or Edge for experiments.'
      });
    }

    // Check for mobile browsers
    if (/android|webos|iphone|ipad|ipod|blackberry|iemobile|opera mini/i.test(userAgent)) {
      this.warnings.push({
        level: 'warning',
        category: 'compatibility',
        message: 'Mobile device detected',
        details: 'Mobile devices may have reduced timing precision and performance.',
        mitigation: 'Use a desktop computer for experiments requiring precise timing.'
      });
    }

    // Check for Safari-specific limitations
    if (userAgent.includes('safari') && !userAgent.includes('chrome')) {
      this.warnings.push({
        level: 'info',
        category: 'compatibility',
        message: 'Safari browser detected',
        details: 'Safari may have limited high-resolution timer access affecting timing precision.',
        mitigation: 'Consider using Chrome or Firefox for better timing accuracy.'
      });
    }
  }

  private checkTimingCapabilities(): void {
    // Check AudioContext availability (required for precise timing)
    if (typeof AudioContext === 'undefined' && typeof (window as any).webkitAudioContext === 'undefined') {
      this.warnings.push({
        level: 'error',
        category: 'feature',
        message: 'No AudioContext support',
        details: 'AudioContext is required for high-precision timing. Timing accuracy will be limited.',
        mitigation: 'Use a browser that supports Web Audio API.'
      });
    }

    // Check performance.now resolution
    const samples: number[] = [];
    for (let i = 0; i < 100; i++) {
      samples.push(performance.now());
    }

    const deltas = [];
    for (let i = 1; i < samples.length; i++) {
      const delta = samples[i] - samples[i - 1];
      if (delta > 0) deltas.push(delta);
    }

    if (deltas.length > 0) {
      const minDelta = Math.min(...deltas);
      if (minDelta > 0.1) { // Greater than 100 microseconds
        this.warnings.push({
          level: 'warning',
          category: 'performance',
          message: 'Low timer resolution',
          details: `Timer resolution is ${minDelta.toFixed(3)}ms. May affect timing precision.`,
          mitigation: 'This is a system limitation. Consider using external timing validation.'
        });
      }
    }

    // Check requestAnimationFrame availability
    if (typeof requestAnimationFrame === 'undefined') {
      this.warnings.push({
        level: 'error',
        category: 'feature',
        message: 'No requestAnimationFrame support',
        details: 'requestAnimationFrame is required for smooth animations.',
        mitigation: 'Use a modern browser with requestAnimationFrame support.'
      });
    }
  }

  /**
   * Display warnings to the user
   */
  displayWarnings(warnings: CapabilityWarning[]): void {
    if (warnings.length === 0) {
      console.log('✅ All system capabilities check passed!');
      return;
    }

    console.group('⚠️ System Capability Warnings');

    const errors = warnings.filter(w => w.level === 'error');
    const warnings_ = warnings.filter(w => w.level === 'warning');
    const info = warnings.filter(w => w.level === 'info');

    if (errors.length > 0) {
      console.group('🚫 Critical Issues');
      errors.forEach(w => {
        console.error(w.message);
        if (w.details) console.error('  Details:', w.details);
        if (w.mitigation) console.error('  Solution:', w.mitigation);
      });
      console.groupEnd();
    }

    if (warnings_.length > 0) {
      console.group('⚠️ Warnings');
      warnings_.forEach(w => {
        console.warn(w.message);
        if (w.details) console.warn('  Details:', w.details);
        if (w.mitigation) console.warn('  Solution:', w.mitigation);
      });
      console.groupEnd();
    }

    if (info.length > 0) {
      console.group('ℹ️ Information');
      info.forEach(w => {
        console.info(w.message);
        if (w.details) console.info('  Details:', w.details);
        if (w.mitigation) console.info('  Tip:', w.mitigation);
      });
      console.groupEnd();
    }

    console.groupEnd();
  }

  /**
   * Create a user-friendly HTML warning display
   */
  createWarningUI(warnings: CapabilityWarning[]): HTMLElement {
    const container = document.createElement('div');
    container.id = 'psyforge-capability-warnings';
    container.style.cssText = `
      position: fixed;
      top: 20px;
      right: 20px;
      max-width: 400px;
      background: white;
      border-radius: 8px;
      box-shadow: 0 4px 6px rgba(0,0,0,0.1);
      padding: 20px;
      z-index: 10000;
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    `;

    const header = document.createElement('h3');
    header.textContent = 'System Compatibility Check';
    header.style.cssText = 'margin: 0 0 15px 0; font-size: 18px;';
    container.appendChild(header);

    if (warnings.length === 0) {
      const success = document.createElement('div');
      success.style.cssText = 'color: #10b981; font-weight: 500;';
      success.textContent = '✅ All checks passed! Your system is ready.';
      container.appendChild(success);
    } else {
      warnings.forEach(warning => {
        const warningEl = document.createElement('div');
        warningEl.style.cssText = `
          margin-bottom: 15px;
          padding: 10px;
          border-radius: 4px;
          background: ${
            warning.level === 'error' ? '#fee2e2' :
            warning.level === 'warning' ? '#fef3c7' : '#dbeafe'
          };
        `;

        const icon = warning.level === 'error' ? '🚫' :
                     warning.level === 'warning' ? '⚠️' : 'ℹ️';

        const title = document.createElement('div');
        title.style.cssText = 'font-weight: 600; margin-bottom: 5px;';
        title.textContent = `${icon} ${warning.message}`;
        warningEl.appendChild(title);

        if (warning.details) {
          const details = document.createElement('div');
          details.style.cssText = 'font-size: 14px; color: #374151; margin-bottom: 5px;';
          details.textContent = warning.details;
          warningEl.appendChild(details);
        }

        if (warning.mitigation) {
          const mitigation = document.createElement('div');
          mitigation.style.cssText = 'font-size: 14px; color: #059669; font-style: italic;';
          mitigation.textContent = `💡 ${warning.mitigation}`;
          warningEl.appendChild(mitigation);
        }

        container.appendChild(warningEl);
      });
    }

    const closeButton = document.createElement('button');
    closeButton.textContent = 'Close';
    closeButton.style.cssText = `
      margin-top: 15px;
      padding: 8px 16px;
      background: #3b82f6;
      color: white;
      border: none;
      border-radius: 4px;
      cursor: pointer;
      font-size: 14px;
    `;
    closeButton.onclick = () => container.remove();
    container.appendChild(closeButton);

    return container;
  }

  /**
   * Check if experiment can run with acceptable performance
   */
  canRunExperiment(requireWebGL2: boolean = false): boolean {
    const capabilities = this.renderer.getCapabilities();

    // Must have at least Canvas2D
    if (!capabilities.canvas2D) {
      return false;
    }

    // If WebGL2 is required, check for it
    if (requireWebGL2 && !capabilities.webGL2) {
      return false;
    }

    // Check for critical errors
    const warnings = this.checkCapabilities();
    const hasErrors = warnings.some(w => w.level === 'error');

    return !hasErrors;
  }
}

