/**
 * WebGL Fallback Demo
 * 
 * This example demonstrates how the ForgeScript renderer handles
 * different WebGL capabilities and falls back to Canvas2D when needed.
 */

import { EnhancedStimulusRenderer } from '../src/stimuli/EnhancedStimulusRenderer';
import { CapabilityChecker } from '../src/validation/CapabilityWarning';
import { Experiment } from '../src/core/Experiment';
import { Timeline } from '../src/core/Timeline';
import { TextStimulusPixi } from '../src/stimuli/TextStimulusPixi';
import { ShapeStimulusPixi } from '../src/stimuli/ShapeStimulusPixi';
import { KeyboardResponse } from '../src/responses/KeyboardResponse';
import { WaitEvent } from '../src/events/WaitEvent';

async function runFallbackDemo() {
  console.log('🔍 WebGL Fallback Demo Starting...\n');

  // Step 1: Check system capabilities
  const capabilityChecker = new CapabilityChecker();
  const warnings = capabilityChecker.checkCapabilities();

  console.log('📊 System Capabilities:');
  const renderer = EnhancedStimulusRenderer.getInstance();
  const capabilities = renderer.getCapabilities();

  console.log(`  Renderer: ${capabilities.renderer}`);
  console.log(`  WebGL2: ${capabilities.webGL2 ? '✅' : '❌'}`);
  console.log(`  WebGL1: ${capabilities.webGL1 ? '✅' : '❌'}`);
  console.log(`  Canvas2D: ${capabilities.canvas2D ? '✅' : '❌'}`);
  console.log(`  Max Texture Size: ${capabilities.maxTextureSize}px`);
  console.log('');

  // Display any warnings
  capabilityChecker.displayWarnings(warnings);

  // Step 2: Initialize renderer with different configurations
  console.log('\n🎮 Testing Different Renderer Configurations...\n');

  // Test 1: Try WebGL2 preferred (default)
  try {
    console.log('Test 1: Initializing with WebGL2 preference...');
    await renderer.initialize({
      width: 800,
      height: 600,
      backgroundColor: 0x1a1a1a,
      preferWebGL2: true,
      enableFallback: true
    });
    console.log(`✅ Initialized with: ${renderer.isUsingFallback() ? 'Canvas2D Fallback' : 'WebGL'}`);
  } catch (error) {
    console.error('❌ Initialization failed:', error);
  }

  // Create a simple experiment to test rendering
  console.log('\n🧪 Running Test Experiment...\n');

  const experiment = Experiment.create()
    .setId('webgl-fallback-test')
    .setName('WebGL Fallback Test')
    .setDescription('Tests rendering with different WebGL capabilities');

  // Create main timeline
  const mainTimeline = Timeline.create('main');

  // Instructions screen
  const instructions = TextStimulusPixi.create('instructions')
    .setText(`Renderer Test\n\nUsing: ${renderer.isUsingFallback() ? 'Canvas2D Fallback' : capabilities.renderer.toUpperCase()}\n\nPress SPACE to continue`)
    .setFontSize(24)
    .setColor('#FFFFFF')
    .setPosition(0, 0);

  mainTimeline.addStimulus(instructions);
  mainTimeline.addEvent(WaitEvent.create().setDuration(1000));
  mainTimeline.addResponse(
    KeyboardResponse.create('continue')
      .setKeys([' '])
      .setWindow([0, Infinity])
  );

  // Test different stimulus types
  const testStimuli = [
    {
      name: 'Text Rendering',
      stimulus: TextStimulusPixi.create('text-test')
        .setText('Text Rendering Test')
        .setFontSize(36)
        .setColor('#00FF00')
    },
    {
      name: 'Rectangle Shape',
      stimulus: ShapeStimulusPixi.create('rect-test')
        .setShapeType('rectangle')
        .setSize(200, 100)
        .setFillColor('#FF0000')
    },
    {
      name: 'Circle Shape',
      stimulus: ShapeStimulusPixi.create('circle-test')
        .setShapeType('circle')
        .setRadius(75)
        .setFillColor('#0000FF')
    }
  ];

  // Test each stimulus type
  for (const test of testStimuli) {
    const testTimeline = Timeline.create(`test-${test.name}`);

    // Show test name
    const label = TextStimulusPixi.create(`label-${test.name}`)
      .setText(test.name)
      .setFontSize(18)
      .setColor('#CCCCCC')
      .setPosition(0, -200);

    testTimeline.addStimulus(label);
    testTimeline.addStimulus(test.stimulus);
    testTimeline.addEvent(WaitEvent.create().setDuration(2000));

    mainTimeline.addChild(testTimeline);
  }

  // Performance test
  const perfTestTimeline = Timeline.create('performance-test');

  const perfLabel = TextStimulusPixi.create('perf-label')
    .setText('Performance Test: 50 Shapes')
    .setFontSize(18)
    .setColor('#CCCCCC')
    .setPosition(0, -250);

  perfTestTimeline.addStimulus(perfLabel);

  // Add many shapes to test performance
  for (let i = 0; i < 50; i++) {
    const angle = (i / 50) * Math.PI * 2;
    const radius = 150;
    const x = Math.cos(angle) * radius;
    const y = Math.sin(angle) * radius;

    const shape = ShapeStimulusPixi.create(`perf-shape-${i}`)
      .setShapeType(i % 2 === 0 ? 'circle' : 'rectangle')
      .setSize(20, 20)
      .setRadius(10)
      .setFillColor(`hsl(${(i / 50) * 360}, 70%, 50%)`)
      .setPosition(x, y);

    perfTestTimeline.addStimulus(shape);
  }

  perfTestTimeline.addEvent(WaitEvent.create().setDuration(3000));
  mainTimeline.addChild(perfTestTimeline);

  // Completion screen
  const completion = TextStimulusPixi.create('completion')
    .setText('Test Complete!\n\nPress ESCAPE to exit')
    .setFontSize(24)
    .setColor('#FFFFFF');

  const completionTimeline = Timeline.create('completion');
  completionTimeline.addStimulus(completion);
  completionTimeline.addResponse(
    KeyboardResponse.create('exit')
      .setKeys(['Escape'])
      .setWindow([0, Infinity])
  );

  mainTimeline.addChild(completionTimeline);

  // Set main timeline
  experiment.setTimeline(mainTimeline);

  // Run the experiment
  try {
    console.log('🚀 Starting experiment...\n');
    const results = await experiment.run();

    console.log('\n📊 Experiment Results:');
    console.log(`  Participant: ${results.participantId}`);
    console.log(`  Duration: ${results.duration}ms`);
    console.log(`  Trials completed: ${results.trials.length}`);
    console.log(`  Renderer used: ${renderer.isUsingFallback() ? 'Canvas2D' : capabilities.renderer}`);

    // Check performance metrics
    const metrics = renderer.getPerformanceMetrics();
    if (metrics) {
      console.log('\n⚡ Performance Metrics:');
      console.log(`  Average FPS: ${metrics.average.fps.toFixed(1)}`);
      console.log(`  Frame time: ${metrics.average.frameTime.toFixed(2)}ms`);
      console.log(`  Memory usage: ${(metrics.average.heapUsed / 1024 / 1024).toFixed(1)}MB`);
    }

  } catch (error) {
    console.error('❌ Experiment error:', error);
  } finally {
    // Cleanup
    renderer.destroy();
  }
}

// Test different fallback scenarios
async function testFallbackScenarios() {
  console.log('\n🔬 Testing Fallback Scenarios...\n');

  // Scenario 1: Force Canvas2D fallback
  console.log('Scenario 1: Force Canvas2D mode');
  const renderer = EnhancedStimulusRenderer.getInstance();

  // Temporarily override getContext to simulate no WebGL
  const originalGetContext = HTMLCanvasElement.prototype.getContext;
  HTMLCanvasElement.prototype.getContext = function(contextType: string) {
    if (contextType === 'webgl' || contextType === 'webgl2') {
      return null;
    }
    return originalGetContext.call(this, contextType);
  };

  try {
    await renderer.initialize({ enableFallback: true });
    console.log('✅ Successfully initialized with Canvas2D fallback');
    console.log(`  Using fallback: ${renderer.isUsingFallback()}`);
  } catch (error) {
    console.error('❌ Failed to initialize:', error);
  } finally {
    // Restore original getContext
    HTMLCanvasElement.prototype.getContext = originalGetContext;
    renderer.destroy();
  }

  // Scenario 2: No fallback allowed
  console.log('\nScenario 2: Disable fallback (WebGL required)');
  try {
    await renderer.initialize({ enableFallback: false });
    console.log('✅ Successfully initialized with WebGL');
  } catch (error) {
    console.log('✅ Correctly threw error when WebGL unavailable:', error.message);
  }
}

// Run the demo
(async () => {
  try {
    // Check if experiment should run
    const checker = new CapabilityChecker();
    if (!checker.canRunExperiment()) {
      console.error('❌ System does not meet minimum requirements to run experiments');

      // Show UI warnings
      const warnings = checker.checkCapabilities();
      const warningUI = checker.createWarningUI(warnings);
      document.body.appendChild(warningUI);

      return;
    }

    // Run the main demo
    await runFallbackDemo();

    // Test fallback scenarios
    await testFallbackScenarios();

  } catch (error) {
    console.error('Demo error:', error);
  }
})();

